var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어지간히 끈질기군...... 이쯤 되면 포기할 법도 한데......","JPN":"とんでもなくしつこいな……いい加減、諦めてもいい頃だが……","ENG":"She's still as tenacious as ever... You'd think she'd give up by now...","TWN":"真是頑強……都到這種地步了，妳也該放棄了吧……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"포기따윈 생각해 본 적도 없다.","JPN":"諦めようなどと考えたことは一度もない。","ENG":"I've never even considered giving up.","TWN":"我從沒想過要放棄。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"명심하도록. 내가 있는 한 너희들은 방주에 손가락 하나 못 대.","JPN":"肝に銘じておけ。私がいる限り、\\n貴様たちは箱舟に指一本触れることはできん。","ENG":"Mark my words. You won't lay a finger on that Ark as long as I live.","TWN":"給我記好了，只要我活著的一天，你們就休想靠近方舟一步。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"큭...... 크큭......","JPN":"クッ……ククッ……","ENG":"Hah... Hah hah...","TWN":"呵……呵呵……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"혼자만 고고한 척 하기는......","JPN":"自分だけ高尚ぶりやがって……","ENG":"Look at you, pretending to be all noble...","TWN":"裝什麼清高……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어차피 우리와 별반 다를 것도 없는 주제에...... 구역질나는군......","JPN":"どうせ俺らと大差ないくせして……反吐が出るぜ……","ENG":"You're no different from us... You make me vomit...","TWN":"妳和我們又沒什麼不同……真令人噁心……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……何だと？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"아...... 젠장. 원본만 잡아먹었다면 나도 이 따위 병정놀이는 진작에 때려치웠을 텐데......","JPN":"クソッ……オリジナルさえ捕まえて喰っていれば、\\n俺もこんなくだらん兵隊ごっこはとっくにやめてるはずなんだが……","ENG":"Oh... Crap. If only I devoured my original... I'd have stopped playing soldier a long time ago...","TWN":"啊……該死，只要吃了本體，我就不用玩這種士兵遊戲了……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"하긴 이젠 너무 늦어버렸나?","JPN":"まあ、もはや何もかも手遅れだがな。","ENG":"Then again, I guess it's too late for that now.","TWN":"但已經太遲了吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 뜻이지? 늦다니 뭐가......?","JPN":"何のことだ？　手遅れとはいったい……？","ENG":"What do you mean? Too late for what?","TWN":"什麼意思？什麼太遲了……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"우리 전대장은 너랑 다르게 부하 목숨 따위는 신경 쓰지 않거든.","JPN":"我らが戦隊長はお前と違って、部下の命など眼中にないお方なのさ。","ENG":"Unlike you, our boss doesn't give a damn about her troops.","TWN":"我們的隊長和妳不同，在她眼裡，部下的性命什麼的，根本就不重要。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이런, 가엾은...... 이름이 뭐더라?","JPN":"おぉ、哀れな……名前は何と言ったかな？","ENG":"Oh, poor thing... What was his name again?","TWN":"哎呀，真可憐……他叫什麼名字來著？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하긴, 뭐든 상관없지. 어차피 곧 재가 될 마당에.","JPN":"まあ、何であろうと構わん。どうせすぐに灰となるのだから。","ENG":"Well, I suppose it doesn't matter. He'll be a pile of ash soon.","TWN":"算了，無所謂，反正很快就會化成灰燼的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"바퀴벌레가 날아가기 전에 잿더미로 만들어 버려라!","JPN":"ゴキブリが飛び立つ前に消し炭にしてしまえ！","ENG":"Turn that Roach into pulp before she flies away!","TWN":"在蟑螂飛走之前把她轟成灰屑！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"포격 개시!","JPN":"砲撃開始！","ENG":"Fire!","TWN":"開始砲擊！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 자식......! 설마 아군을 미끼로 삼다니!","JPN":"こいつ……！　まさか、味方を囮にするとは！","ENG":"That scumbag! She's used her own troops as bait!","TWN":"這傢伙……！竟然把自己人當成誘餌！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};